import json
import logging
from google.cloud import storage, firestore, pubsub_v1
from google.cloud.exceptions import NotFound

def process_file_from_gcs(event, context):
    """Triggered by a change to a Cloud Storage bucket.
    Args:
        event (dict): Event payload.
        context (google.cloud.functions.Context): Metadata for the event.
    """
    # Initialize clients
    storage_client = storage.Client()
    firestore_client = firestore.Client()
    pubsub_client = pubsub_v1.PublisherClient()
    
    # Get bucket and file information
    bucket_name = event['bucket']
    file_name = event['name']
    
    # Download file from Cloud Storage
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    try:
        # Read file content
        file_content = blob.download_as_text()
        
        # Process file content (example: parse JSON)
        try:
            data = json.loads(file_content)
        except json.JSONDecodeError:
            data = {"content": file_content, "file_name": file_name}
        
        # Write to Firestore
        collection_ref = firestore_client.collection('processed_files')
        doc_ref = collection_ref.document(file_name)
        doc_ref.set({
            'data': data,
            'processed_at': firestore.SERVER_TIMESTAMP,
            'file_name': file_name,
            'bucket_name': bucket_name
        })
        
        # Publish to Pub/Sub
        topic_path = pubsub_client.topic_path('your-project-id', 'your-topic-name')
        message_data = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'processed_at': str(firestore.SERVER_TIMESTAMP)
        }
        
        pubsub_client.publish(
            topic=topic_path,
            data=json.dumps(message_data).encode('utf-8')
        )
        
        logging.info(f'Successfully processed file: {file_name}')
        
    except Exception as e:
        logging.error(f'Error processing file {file_name}: {str(e)}')
        raise e